from math import exp

def concentracion(t: float) -> float:
    if t < 0:
        raise ValueError('t debe ser no negativo')
    return 80.0 * exp(-0.25 * t)

def derivada_central(f, x: float, h: float) -> float:
    if h <= 0:
        raise ValueError('h debe ser positivo')
    return (f(x + h) - f(x - h)) / (2.0 * h)

x = 4.0
h = 0.1
aproximada = derivada_central(concentracion, x, h)
analitica = -20.0 * exp(-0.25 * x)
error = abs(aproximada - analitica)
print(aproximada, analitica, error)

